#!/usr/bin/env python

import os
import sys
import time
import tarfile
import zipfile
import subprocess
import shutil
from datetime import datetime

def create_backup(source_dir, output_format='tar.gz', output_dir=None):
    if not os.path.exists(source_dir):
        print("Error: Source directory does not exist: {}".format(source_dir))
        return False
    
    if not os.path.isdir(source_dir):
        print("Error: Path is not a directory: {}".format(source_dir))
        return False
    
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    dir_name = os.path.basename(os.path.normpath(source_dir))
    
    if output_dir is None:
        output_dir = os.path.dirname(source_dir) or '.'
    
    if not os.path.exists(output_dir):
        os.makedirs(output_dir)
    
    output_format = output_format.lower()
    
    if output_format == 'tar.gz':
        archive_name = os.path.join(output_dir, '{}_{}.tar.gz'.format(dir_name, timestamp))
        return create_tar_gz(source_dir, archive_name)
    elif output_format == 'tar.bz2':
        archive_name = os.path.join(output_dir, '{}_{}.tar.bz2'.format(dir_name, timestamp))
        return create_tar_bz2(source_dir, archive_name)
    elif output_format == 'zip':
        archive_name = os.path.join(output_dir, '{}_{}.zip'.format(dir_name, timestamp))
        return create_zip(source_dir, archive_name)
    elif output_format == '7z':
        archive_name = os.path.join(output_dir, '{}_{}.7z'.format(dir_name, timestamp))
        return create_7z(source_dir, archive_name)
    else:
        print("Error: Unsupported format: {}".format(output_format))
        print("Supported formats: tar.gz, tar.bz2, zip, 7z")
        return False

def create_tar_gz(source_dir, archive_name):
    try:
        print("Creating tar.gz archive: {}".format(archive_name))
        tar = tarfile.open(archive_name, 'w:gz')
        tar.add(source_dir, arcname=os.path.basename(source_dir))
        tar.close()
        print("Success: Archive created at {}".format(archive_name))
        print("Size: {} bytes".format(os.path.getsize(archive_name)))
        return True
    except Exception as e:
        print("Error creating tar.gz archive: {}".format(str(e)))
        return False

def create_tar_bz2(source_dir, archive_name):
    try:
        print("Creating tar.bz2 archive: {}".format(archive_name))
        tar = tarfile.open(archive_name, 'w:bz2')
        tar.add(source_dir, arcname=os.path.basename(source_dir))
        tar.close()
        print("Success: Archive created at {}".format(archive_name))
        print("Size: {} bytes".format(os.path.getsize(archive_name)))
        return True
    except Exception as e:
        print("Error creating tar.bz2 archive: {}".format(str(e)))
        return False

def create_zip(source_dir, archive_name):
    try:
        print("Creating zip archive: {}".format(archive_name))
        zipf = zipfile.ZipFile(archive_name, 'w', zipfile.ZIP_DEFLATED)
        
        for root, dirs, files in os.walk(source_dir):
            for file in files:
                file_path = os.path.join(root, file)
                arcname = os.path.relpath(file_path, os.path.dirname(source_dir))
                zipf.write(file_path, arcname)
        
        zipf.close()
        print("Success: Archive created at {}".format(archive_name))
        print("Size: {} bytes".format(os.path.getsize(archive_name)))
        return True
    except Exception as e:
        print("Error creating zip archive: {}".format(str(e)))
        return False

def create_7z(source_dir, archive_name):
    seven_zip = find_7z_executable()
    
    if not seven_zip:
        print("Error: 7z executable not found. Please install p7zip or 7-Zip")
        return False
    
    try:
        print("Creating 7z archive: {}".format(archive_name))
        cmd = [seven_zip, 'a', '-t7z', archive_name, source_dir]
        process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        stdout, stderr = process.communicate()
        
        if process.returncode != 0:
            print("Error creating 7z archive: {}".format(stderr.decode('utf-8')))
            return False
        
        print("Success: Archive created at {}".format(archive_name))
        print("Size: {} bytes".format(os.path.getsize(archive_name)))
        return True
    except Exception as e:
        print("Error creating 7z archive: {}".format(str(e)))
        return False

def find_7z_executable():
    possible_names = ['7z', '7za', '7zr', 'p7zip']
    
    for name in possible_names:
        if shutil.which(name):
            return name
    
    common_paths = [
        '/usr/bin/7z',
        '/usr/bin/7za',
        '/usr/local/bin/7z',
        '/usr/local/bin/7za',
        'C:\\Program Files\\7-Zip\\7z.exe',
        'C:\\Program Files (x86)\\7-Zip\\7z.exe'
    ]
    
    for path in common_paths:
        if os.path.isfile(path) and os.access(path, os.X_OK):
            return path
    
    return None

def print_usage():
    print("Usage: python backup.py <directory_path> [format] [output_dir]")
    print("")
    print("Arguments:")
    print("  directory_path  - Path to the directory to backup")
    print("  format         - Compression format (default: tar.gz)")
    print("                   Options: tar.gz, tar.bz2, zip, 7z")
    print("  output_dir     - Output directory for archive (default: parent of source)")
    print("")
    print("Examples:")
    print("  python backup.py /home/user/mydata")
    print("  python backup.py /home/user/mydata tar.bz2")
    print("  python backup.py /home/user/mydata zip /backups")

def main():
    if len(sys.argv) < 2:
        print_usage()
        sys.exit(1)
    
    source_dir = sys.argv[1]
    output_format = 'tar.gz'
    output_dir = None
    
    if len(sys.argv) >= 3:
        output_format = sys.argv[2]
    
    if len(sys.argv) >= 4:
        output_dir = sys.argv[3]
    
    success = create_backup(source_dir, output_format, output_dir)
    
    if success:
        sys.exit(0)
    else:
        sys.exit(1)

if __name__ == '__main__':
    main()